```powershell
$capitales = @{
    France   = "Paris"
    Espagne  = "Madrid"
    Italie   = "Rome"
}

# Toutes les clés
$capitales.Keys

# Toutes les valeurs
$capitales.Values

# Itérer sur les paires
foreach ($paire in $capitales.GetEnumerator()) {
    Write-Host "$($paire.Key) → $($paire.Value)"
}

# Trier par clé
$capitales.GetEnumerator() | Sort-Object Key | ForEach-Object {
    Write-Host "$($_.Key) : $($_.Value)"
}

# Hashtable ordonnée (preserve l'ordre d'insertion)
$config = [ordered]@{
    Host = "localhost"
    Port = 5432
    DB   = "production"
}
```

